      const numbers = Object.keys(this.wordToNumberMap);
      const grammar = `#JSGF V1.0; grammar numbers; public <number> = ${numbers.join(' | ')};`;

      speechRecognitionList.addFromString(grammar, 1);

      this.recognition.grammars = speechRecognitionList;
      this.recognition.continuous = false;
      this.recognition.lang = 'en-US';
      this.recognition.interimResults = false;
      this.recognition.maxAlternatives = 1;

      this.recognition.onresult = (event: any) => {
        const last = event.results.length - 1;
        const transcript = event.results[last][0].transcript.toLowerCase().trim().replace('.', '');
        console.log(`[SpeechService] onresult: Received transcript: "${transcript}"`);
        const number = this.wordToNumberMap[transcript];

        if (number !== undefined) {
          console.log(`[SpeechService] onresult: Parsed number: ${number}`);
          this.recognizedNumberSubject.next(number);
        } else {
            console.warn(`[SpeechService] onresult: Transcript "${transcript}" not in number map.`);
        }
        this.stopListening();
      };

      this.recognition.onspeechend = () => {
        console.log('[SpeechService] onspeechend: Speech has ended.');
        this.stopListening();
      };

      this.recognition.onnomatch = () => {
        console.warn('[SpeechService] onnomatch: Speech not recognized.');
        this.error.set("I didn't recognize that number.");
        this.stopListening();
      }

      this.recognition.onerror = (event: any) => {
        console.error(`[SpeechService] onerror: Error occurred:`, event.error);
        if (event.error !== 'no-speech') {
            this.error.set(event.error);
        }
        this.stopListening();
      };
      console.log('[SpeechService] initialize: Setup complete.');
    } catch (e) {
        console.error('[SpeechService] initialize: CRITICAL ERROR during setup.', e);
        this.isSupported.set(false);
        this.microphoneDetected.set(false);
        this.error.set('Could not initialize speech recognition.');
    }
  }

  private async checkMicrophonePresence() {
      console.log('[SpeechService] checkMicrophonePresence: Checking for audio input devices.');
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
          console.warn('[SpeechService] checkMicrophonePresence: mediaDevices API not supported.');
          this.microphoneDetected.set(false);
          return;
      }

      try {
          const devices = await navigator.mediaDevices.enumerateDevices();
          const hasMicrophone = devices.some(d => d.kind === 'audioinput');
          console.log(`[SpeechService] checkMicrophonePresence: Microphone found: ${hasMicrophone}`);
          this.microphoneDetected.set(hasMicrophone);
      } catch (e) {
          console.error('[SpeechService] checkMicrophonePresence: Error checking for microphone:', e);
          this.microphoneDetected.set(false);
      }
  }

  startListening() {
    if (!this.isSupported()) {
        console.log('[SpeechService] startListening: Aborted, not supported.');
        return;
    }
    if (this.isListening()) {
        console.log('[SpeechService] startListening: Aborted, already listening.');
        return;
    }
    console.log('[SpeechService] startListening: Starting recognition.');
    this.isListening.set(true);
    this.error.set(null);
    try {
        this.recognition.start();
    } catch(e) {
        console.error('[SpeechService] startListening: Error starting recognition.', e);
        this.isListening.set(false);
        this.error.set("Microphone already in use.");
    }
  }

  stopListening() {
    if (!this.isSupported()) {
        // console.log('[SpeechService] stopListening: Aborted, not supported.');
        return;
    }
    if (!this.isListening()) {
        // This log can be noisy if called multiple times, which it often is.
        // console.log('[SpeechService] stopListening: Aborted, not currently listening.');
        return;
    }
    console.log('[SpeechService] stopListening: Stopping recognition.');
    this.isListening.set(false);
    this.recognition.stop();
  }
}

import { Component, ChangeDetectionStrategy, inject, signal, computed, effect, OnDestroy } from '@angular/core';
import { Subscription } from 'rxjs';

import { MathService } from './services/math.service';
import { SpeechRecognitionService } from './services/speech-recognition.service';
import { Level, Problem } from './models';

type GameState = 'level-select' | 'playing' | 'feedback' | 'game-over';
type Feedback = 'correct' | 'incorrect' | 'time-up' | null;

const TIME_PER_QUESTION = 3; // 3 seconds
const QUESTIONS_PER_LEVEL = 10;

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AppComponent implements OnDestroy {
  private mathService = inject(MathService);
  speechService = inject(SpeechRecognitionService);

  levels = signal<Level[]>(this.mathService.getLevels());

  gameState = signal<GameState>('level-select');
  selectedLevel = signal<Level | null>(null);
  problems = signal<Problem[]>([]);
  currentProblemIndex = signal(0);
  score = signal(0);

  timeLeft = signal(TIME_PER_QUESTION);
  feedback = signal<Feedback>(null);

  showFireworks = signal(false);
  fireworks = signal<{ style: string }[]>([]);

  private timerInterval: any = null;
  private speechSubscription: Subscription;

  currentProblem = computed(() => {
    const p = this.problems();
    const i = this.currentProblemIndex();
    return p.length > i ? p[i] : null;
  });

  timerProgress = computed(() => {
    return (this.timeLeft() / TIME_PER_QUESTION) * 100;
  });

  constructor() {
    console.log('[AppComponent] Constructor: Initializing component.');
    this.speechSubscription = this.speechService.recognizedNumber$.subscribe(num => {
      console.log(`[AppComponent] Speech subscription received number: ${num}`);
      this.handleAnswer(num);
    });

    console.log('[AppComponent] Constructor: Creating effect for gameState.');
    effect((onCleanup) => {
        const state = this.gameState();
        console.log(`[AppComponent] Effect triggered. gameState is now: '${state}'`);

        if (state === 'playing') {
            console.log('[AppComponent] Effect: gameState is "playing", calling startQuestion().');
            this.startQuestion();
        }

        onCleanup(() => {
            console.log(`[AppComponent] Effect cleanup running for previous state.`);
            this.clearTimer();
            // The check for isListening() is handled inside the service method.
            // Reading the signal here created an infinite loop.
            this.speechService.stopListening();
        });
    });
  }

  ngOnDestroy() {
    console.log('[AppComponent] OnDestroy: Cleaning up component.');
    this.clearTimer();
    this.speechSubscription?.unsubscribe();
  }

  selectLevel(level: Level) {
    console.log(`[AppComponent] selectLevel: Selected level '${level.name}'.`);
    this.selectedLevel.set(level);
    this.problems.set(this.mathService.shuffleAndSampleProblems(level.problems, QUESTIONS_PER_LEVEL));
    this.currentProblemIndex.set(0);
    this.score.set(0);
    console.log('[AppComponent] selectLevel: Setting gameState to "playing".');
    this.gameState.set('playing');
  }

  startQuestion() {
    console.log(`[AppComponent] startQuestion: Starting question #${this.currentProblemIndex() + 1}`);
    this.feedback.set(null);
    this.timeLeft.set(TIME_PER_QUESTION);
    this.speechService.startListening();
    this.startTimer();
  }

  startTimer() {
    console.log('[AppComponent] startTimer: Starting timer.');
    this.clearTimer();
    this.timerInterval = setInterval(() => {
      this.timeLeft.update(t => t - 1);
      if (this.timeLeft() <= 0) {
        console.log('[AppComponent] startTimer: Timer reached 0.');
        this.handleTimeUp();
      }
    }, 1000);
  }

  handleAnswer(answer: number) {
    if (this.gameState() !== 'playing') {
        console.log(`[AppComponent] handleAnswer: Received answer '${answer}', but gameState is '${this.gameState()}'. Ignoring.`);
        return;
    }
    console.log(`[AppComponent] handleAnswer: Handling answer '${answer}'.`);
    this.clearTimer();
    this.speechService.stopListening();

    const problem = this.currentProblem();
    if (problem && answer === problem.answer) {
      console.log('[AppComponent] handleAnswer: Answer is CORRECT.');
      this.feedback.set('correct');
      this.score.update(s => s + 1);
      this.triggerFireworks();
    } else {
      console.log(`[AppComponent] handleAnswer: Answer is INCORRECT. Expected: ${problem?.answer}`);
      this.feedback.set('incorrect');
    }
    console.log('[AppComponent] handleAnswer: Setting gameState to "feedback".');
    this.gameState.set('feedback');
    setTimeout(() => this.nextQuestion(), 1500);
  }

  handleTimeUp() {
    if (this.gameState() !== 'playing') {
        console.log(`[AppComponent] handleTimeUp: Time is up, but gameState is '${this.gameState()}'. Ignoring.`);
        return;
    }
    console.log('[AppComponent] handleTimeUp: Time is up.');
    this.clearTimer();
    this.speechService.stopListening();
    this.feedback.set('time-up');
    console.log('[AppComponent] handleTimeUp: Setting gameState to "feedback".');
    this.gameState.set('feedback');
    setTimeout(() => this.nextQuestion(), 1500);
  }

  nextQuestion() {
    console.log('[AppComponent] nextQuestion: Moving to next question.');
    this.showFireworks.set(false);
    if (this.currentProblemIndex() < this.problems().length - 1) {
      this.currentProblemIndex.update(i => i + 1);
      console.log('[AppComponent] nextQuestion: Setting gameState to "playing".');
      this.gameState.set('playing');
    } else {
      console.log('[AppComponent] nextQuestion: All questions answered. Setting gameState to "game-over".');
      this.gameState.set('game-over');
    }
  }

  restart() {
    console.log('[AppComponent] restart: Restarting game.');
    this.showFireworks.set(false);
    console.log('[AppComponent] restart: Setting gameState to "level-select".');
    this.gameState.set('level-select');
    this.selectedLevel.set(null);
    this.problems.set([]);
  }

  private triggerFireworks() {
    console.log('[AppComponent] triggerFireworks: Triggering fireworks effect.');
    const stars = Array.from({ length: 40 }, () => {
      const angle = Math.random() * 2 * Math.PI;
      const radius = Math.random() * 150 + 50; // spread radius
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;
      const delay = Math.random() * 0.3;
      const duration = 0.8 + Math.random() * 0.4;

      return {
          style: `
              --transform-end: translate(${x}px, ${y}px) scale(${Math.random() * 0.5 + 0.5});
              animation-delay: ${delay}s;
              animation-duration: ${duration}s;
          `
      };
    });
    this.fireworks.set(stars);
    this.showFireworks.set(true);
  }

  private clearTimer() {
    if (this.timerInterval) {
      console.log('[AppComponent] clearTimer: Clearing existing timer interval.');
      clearInterval(this.timerInterval);
      this.timerInterval = null;
    }
  }
}

