import { Component, ChangeDetectionStrategy, signal, OnDestroy, AfterViewInit } from '@angular/core';

@Component({
  selector: 'mic-test',
  standalone: true,
  template: `
    <div class="bg-slate-800/50 border border-slate-700 rounded-lg p-4 mb-8 max-w-md mx-auto">
      <h3 class="text-lg font-bold text-slate-200 mb-2">Microphone Check</h3>
      @if (error()) {
        <p class="text-red-400 text-sm">{{ error() }}</p>
      } @else {
        <p class="text-slate-400 text-sm mb-3">Speak into your microphone. The bars should light up.</p>
        <div class="flex items-end justify-center h-16 space-x-1">
            @for (bar of bars; track $index) {
                <div 
                    class="w-4 rounded-t-sm transition-all duration-100"
                    [class.bg-green-500]="volume() > $index * 10"
                    [class.bg-slate-700]="volume() <= $index * 10"
                    [style.height.%]="($index + 1) * 10"
                ></div>
            }
        </div>
      }
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MicTestComponent implements AfterViewInit, OnDestroy {
  volume = signal(0);
  error = signal<string | null>(null);
  bars = Array(10); // for the 10 visualizer bars

  private audioContext: AudioContext | null = null;
  private analyser: AnalyserNode | null = null;
  private dataArray: Uint8Array | null = null;
  private source: MediaStreamAudioSourceNode | null = null;
  private stream: MediaStream | null = null;
  private animationFrameId: number | null = null;

  ngAfterViewInit() {
    this.initMic();
  }

  private async initMic() {
    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        this.error.set('Microphone access is not supported by this browser.');
        return;
      }

      this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      this.audioContext = new AudioContext();
      this.analyser = this.audioContext.createAnalyser();
      this.source = this.audioContext.createMediaStreamSource(this.stream);

      this.analyser.fftSize = 256;
      const bufferLength = this.analyser.frequencyBinCount;
      this.dataArray = new Uint8Array(bufferLength);

      this.source.connect(this.analyser);
      this.draw();

    } catch (err) {
      console.error('Error accessing microphone:', err);
      this.error.set('Microphone access denied. Please allow microphone permissions in your browser settings and refresh.');
    }
  }

  private draw = () => {
    if (!this.analyser || !this.dataArray) return;

    this.animationFrameId = requestAnimationFrame(this.draw);

    this.analyser.getByteFrequencyData(this.dataArray);

    let sum = 0;
    for (const amplitude of this.dataArray) {
      sum += amplitude * amplitude;
    }
    // Calculate RMS and scale to a 0-100 range
    const rms = Math.sqrt(sum / this.dataArray.length);
    const volumeLevel = Math.min(100, Math.max(0, rms * 2)); // scaling factor of 2 seems to work well
    this.volume.set(volumeLevel);
  };

  ngOnDestroy() {
    if (this.animationFrameId) {
      cancelAnimationFrame(this.animationFrameId);
    }
    if (this.stream) {
      this.stream.getTracks().forEach(track => track.stop());
    }
    if (this.audioContext) {
      this.audioContext.close();
    }
  }
}

