@Injectable({ providedIn: 'root' })
export class SpeechRecognitionService {
  private recognition: any | null = null;
  private wordToNumberMap: { [key: string]: number } = {
    'zero': 0, 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
    'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10,
    'eleven': 11, 'twelve': 12, 'thirteen': 13, 'fourteen': 14, 'fifteen': 15,
    'sixteen': 16, 'seventeen': 17, 'eighteen': 18, 'nineteen': 19, 'twenty': 20
  };

  isSupported = signal(false);
  microphoneDetected = signal<boolean | 'pending'>('pending');
  isListening = signal(false);
  error = signal<string | null>(null);
  lastTranscript = signal<string>('');
  private recognizedNumberSubject = new Subject<number>();
  recognizedNumber$ = this.recognizedNumberSubject.asObservable();

  constructor() {
    this.initialize();
  }

  private initialize() {
    try {
      // FIX: Property 'SpeechRecognition' does not exist on type 'Window'. Cast to `any` for access.
      const SpeechRecognitionAPI = (window as any).SpeechRecognition || webkitSpeechRecognition;
      // FIX: Property 'SpeechGrammarList' does not exist on type 'Window'. Cast to `any` for access.
      const SpeechGrammarListAPI = (window as any).SpeechGrammarList || webkitSpeechGrammarList;

      if (!SpeechRecognitionAPI || !SpeechGrammarListAPI) {
        this.isSupported.set(false);
        this.microphoneDetected.set(false);
        this.error.set('Speech recognition is not supported in this browser.');
        return;
      }

      this.isSupported.set(true);
      this.checkMicrophonePresence();

      this.recognition = new SpeechRecognitionAPI();
      const speechRecognitionList = new SpeechGrammarListAPI();

      const numbers = Object.keys(this.wordToNumberMap);
      const grammar = `#JSGF V1.0; grammar numbers; public <number> = ${numbers.join(' | ')};`;

      speechRecognitionList.addFromString(grammar, 1);

      this.recognition.grammars = speechRecognitionList;
      this.recognition.continuous = false;
      this.recognition.lang = 'en-US';
      this.recognition.interimResults = false;
      this.recognition.maxAlternatives = 1;

      this.recognition.onresult = (event: any) => {
        const last = event.results.length - 1;
        const transcript = event.results[last][0].transcript.toLowerCase().trim().replace('.', '');

        this.lastTranscript.set(transcript);

        const number = this.wordToNumberMap[transcript];

        if (number !== undefined) {
          this.recognizedNumberSubject.next(number);
        }
      };

      this.recognition.onspeechend = () => {
        this.stopListening();
      };

      this.recognition.onnomatch = () => {
        this.error.set("I didn't recognize that number.");
        this.stopListening();
      }

      this.recognition.onerror = (event: any) => {
        if (event.error !== 'no-speech') {
            this.error.set(event.error);
        }
        this.stopListening();
      };
    } catch (e) {
        this.isSupported.set(false);
        this.microphoneDetected.set(false);
        this.error.set('Could not initialize speech recognition.');
    }
  }

  private async checkMicrophonePresence() {
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
          this.microphoneDetected.set(false);
          return;
      }

      try {
          const devices = await navigator.mediaDevices.enumerateDevices();
          const hasMicrophone = devices.some(d => d.kind === 'audioinput');
          this.microphoneDetected.set(hasMicrophone);
      } catch (e) {
          this.microphoneDetected.set(false);
      }
  }

  startListening() {
    if (!this.isSupported() || this.isListening()) {
        return;
    }
    this.isListening.set(true);
    this.error.set(null);
    this.lastTranscript.set('');
    try {
        this.recognition.start();
    } catch(e) {
        this.isListening.set(false);
        this.error.set("Microphone already in use.");
    }
  }

  stopListening() {
    if (!this.isSupported() || !this.isListening()) {
        return;
    }
    this.isListening.set(false);
    this.recognition.stop();
  }
}

import { Component, ChangeDetectionStrategy, inject, signal, computed, effect, OnDestroy, untracked } from '@angular/core';
import { Subscription } from 'rxjs';

import { MathService } from './services/math.service';
import { SpeechRecognitionService } from './services/speech-recognition.service';
import { Level, Problem } from './models';
import { MicTestComponent } from './mic-test.component';
import { SpeechTestComponent } from './speech-test.component';

type GameState = 'level-select' | 'playing' | 'feedback' | 'game-over';
type Feedback = 'correct' | 'incorrect' | 'time-up' | null;

const TIME_PER_QUESTION = 3; // 3 seconds
const QUESTIONS_PER_LEVEL = 10;

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [MicTestComponent, SpeechTestComponent],
})
export class AppComponent implements OnDestroy {
  private mathService = inject(MathService);
  speechService = inject(SpeechRecognitionService);

  levels = signal<Level[]>(this.mathService.getLevels());

  gameState = signal<GameState>('level-select');
  selectedLevel = signal<Level | null>(null);
  problems = signal<Problem[]>([]);
  currentProblemIndex = signal(0);
  score = signal(0);

  timeLeft = signal(TIME_PER_QUESTION);
  feedback = signal<Feedback>(null);

  showFireworks = signal(false);
  fireworks = signal<{ style: string }[]>([]);

  private timerInterval: any = null;
  private speechSubscription: Subscription;

  currentProblem = computed(() => {
    const p = this.problems();
    const i = this.currentProblemIndex();
    return p.length > i ? p[i] : null;
  });

  timerProgress = computed(() => {
    return (this.timeLeft() / TIME_PER_QUESTION) * 100;
  });

  constructor() {
    this.speechSubscription = this.speechService.recognizedNumber$.subscribe(num => {
      this.handleAnswer(num);
    });

    effect((onCleanup) => {
        const state = this.gameState();

        if (state === 'playing') {
            untracked(() => this.startQuestion());
        }

        onCleanup(() => {
            untracked(() => {
              this.clearTimer();
              this.speechService.stopListening();
            });
        });
    });
  }

  ngOnDestroy() {
    this.clearTimer();
    this.speechSubscription?.unsubscribe();
  }

  selectLevel(level: Level) {
    this.selectedLevel.set(level);
    this.problems.set(this.mathService.shuffleAndSampleProblems(level.problems, QUESTIONS_PER_LEVEL));
    this.currentProblemIndex.set(0);
    this.score.set(0);
    this.gameState.set('playing');
  }

  startQuestion() {
    this.feedback.set(null);
    this.timeLeft.set(TIME_PER_QUESTION);
    this.speechService.startListening();
    this.startTimer();
  }

  startTimer() {
    this.clearTimer();
    this.timerInterval = setInterval(() => {
      this.timeLeft.update(t => t - 1);
      if (this.timeLeft() <= 0) {
        this.handleTimeUp();
      }
    }, 1000);
  }

  handleAnswer(answer: number) {
    if (this.gameState() !== 'playing') return;

    console.log(`[Speech Debug] Heard: ${answer}`);

    this.clearTimer();
    this.speechService.stopListening();

    const problem = this.currentProblem();
    if (problem && answer === problem.answer) {
      this.feedback.set('correct');
      this.score.update(s => s + 1);
      this.triggerFireworks();
    } else {
      this.feedback.set('incorrect');
    }
    this.gameState.set('feedback');
    setTimeout(() => this.nextQuestion(), 1500);
  }

  handleTimeUp() {
    if (this.gameState() !== 'playing') return;

    console.log('[Speech Debug] No input detected.');

    this.clearTimer();
    this.speechService.stopListening();
    this.feedback.set('time-up');
    this.gameState.set('feedback');
    setTimeout(() => this.nextQuestion(), 1500);
  }

  nextQuestion() {
    this.showFireworks.set(false);
    if (this.currentProblemIndex() < this.problems().length - 1) {
      this.currentProblemIndex.update(i => i + 1);
      this.gameState.set('playing');
    } else {
      this.gameState.set('game-over');
    }
  }

  restart() {
    this.showFireworks.set(false);
    this.gameState.set('level-select');
    this.selectedLevel.set(null);
    this.problems.set([]);
  }

  private triggerFireworks() {
    const stars = Array.from({ length: 40 }, () => {
      const angle = Math.random() * 2 * Math.PI;
      const radius = Math.random() * 150 + 50; // spread radius
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;
      const delay = Math.random() * 0.3;
      const duration = 0.8 + Math.random() * 0.4;

      return {
          style: `
              --transform-end: translate(${x}px, ${y}px) scale(${Math.random() * 0.5 + 0.5});
              animation-delay: ${delay}s;
              animation-duration: ${duration}s;
          `
      };
    });
    this.fireworks.set(stars);
    this.showFireworks.set(true);
  }

  private clearTimer() {
    if (this.timerInterval) {
      clearInterval(this.timerInterval);
      this.timerInterval = null;
    }
  }
}

import { Component, ChangeDetectionStrategy, signal, OnDestroy, AfterViewInit } from '@angular/core';

@Component({
  selector: 'mic-test',
  standalone: true,
  template: `
    <div class="bg-slate-800/50 border border-slate-700 rounded-lg p-4 w-full max-w-xs mx-auto">
      <h3 class="text-lg font-bold text-slate-200 mb-2">Mic Level</h3>
      @if (error()) {
        <p class="text-red-400 text-sm">{{ error() }}</p>
      } @else {
        <p class="text-slate-400 text-sm mb-3">The bars should react to your voice.</p>
        <div class="flex items-end justify-center h-16 space-x-1">
            @for (bar of bars; track $index) {
                <div 
                    class="w-4 rounded-t-sm transition-all duration-100"
                    [class.bg-green-500]="volume() > $index * 10"
                    [class.bg-slate-700]="volume() <= $index * 10"
                    [style.height.%]="($index + 1) * 10"
                ></div>
            }
        </div>
      }
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MicTestComponent implements AfterViewInit, OnDestroy {
  volume = signal(0);
  error = signal<string | null>(null);
  bars = Array(10); // for the 10 visualizer bars

  private audioContext: AudioContext | null = null;
  private analyser: AnalyserNode | null = null;
  private dataArray: Uint8Array | null = null;
  private source: MediaStreamAudioSourceNode | null = null;
  private stream: MediaStream | null = null;
  private animationFrameId: number | null = null;

  ngAfterViewInit() {
    this.initMic();
  }

  private async initMic() {
    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        this.error.set('Microphone access is not supported by this browser.');
        return;
      }

      this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      this.audioContext = new AudioContext();
      this.analyser = this.audioContext.createAnalyser();
      this.source = this.audioContext.createMediaStreamSource(this.stream);

      this.analyser.fftSize = 256;
      const bufferLength = this.analyser.frequencyBinCount;
      this.dataArray = new Uint8Array(bufferLength);

      this.source.connect(this.analyser);
      this.draw();

    } catch (err) {
      console.error('Error accessing microphone:', err);
      this.error.set('Microphone access denied. Please allow microphone permissions in your browser settings and refresh.');
    }
  }

  private draw = () => {
    if (!this.analyser || !this.dataArray) return;

    this.animationFrameId = requestAnimationFrame(this.draw);

    // Use getByteTimeDomainData for a more accurate volume reading
    this.analyser.getByteTimeDomainData(this.dataArray);

    let sumSquares = 0.0;
    for (const amplitude of this.dataArray) {
        // The data is an unsigned byte, 128 is the zero-crossing (silence)
        const normalizedSample = (amplitude / 128.0) - 1.0; // convert to a -1.0 to 1.0 range
        sumSquares += normalizedSample * normalizedSample;
    }

    // Calculate RMS (Root Mean Square) and scale to a 0-100 range
    const rms = Math.sqrt(sumSquares / this.dataArray.length);
    const volumeLevel = Math.min(100, Math.max(0, rms * 250)); // Multiplier scales the RMS to a nice visual range
    this.volume.set(volumeLevel);
  };

  ngOnDestroy() {
    if (this.animationFrameId) {
      cancelAnimationFrame(this.animationFrameId);
    }
    if (this.stream) {
      this.stream.getTracks().forEach(track => track.stop());
    }
    if (this.audioContext) {
      this.audioContext.close();
    }
  }
}

