import { Injectable, signal } from '@angular/core';
import { Subject } from 'rxjs';

declare var SpeechRecognition: any;
declare var webkitSpeechRecognition: any;
declare var SpeechGrammarList: any;
declare var webkitSpeechGrammarList: any;

@Injectable({ providedIn: 'root' })
export class SpeechRecognitionService {
  private recognition: any | null = null;
  private wordToNumberMap: { [key: string]: number } = {
    'zero': 0, 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
    'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10,
    'eleven': 11, 'twelve': 12, 'thirteen': 13, 'fourteen': 14, 'fifteen': 15,
    'sixteen': 16, 'seventeen': 17, 'eighteen': 18, 'nineteen': 19, 'twenty': 20
  };

  isSupported = signal(false);
  microphoneDetected = signal<boolean | 'pending'>('pending');
  isListening = signal(false);
  error = signal<string | null>(null);
  lastTranscript = signal<string>('');
  private recognizedNumberSubject = new Subject<number>();
  recognizedNumber$ = this.recognizedNumberSubject.asObservable();

  constructor() {
    this.initialize();
  }

  private initialize() {
    try {
      // FIX: Property 'SpeechRecognition' does not exist on type 'Window'. Cast to `any` for access.
      const SpeechRecognitionAPI = (window as any).SpeechRecognition || webkitSpeechRecognition;
      // FIX: Property 'SpeechGrammarList' does not exist on type 'Window'. Cast to `any` for access.
      const SpeechGrammarListAPI = (window as any).SpeechGrammarList || webkitSpeechGrammarList;

      if (!SpeechRecognitionAPI || !SpeechGrammarListAPI) {
        this.isSupported.set(false);
        this.microphoneDetected.set(false);
        this.error.set('Speech recognition is not supported in this browser.');
        return;
      }

      this.isSupported.set(true);
      this.checkMicrophonePresence();

      this.recognition = new SpeechRecognitionAPI();
      const speechRecognitionList = new SpeechGrammarListAPI();

      const numbers = Object.keys(this.wordToNumberMap);
      const grammar = `#JSGF V1.0; grammar numbers; public <number> = ${numbers.join(' | ')};`;

      speechRecognitionList.addFromString(grammar, 1);

      this.recognition.grammars = speechRecognitionList;
      this.recognition.continuous = false;
      this.recognition.lang = 'en-US';
      this.recognition.interimResults = false;
      this.recognition.maxAlternatives = 1;

      this.recognition.onresult = (event: any) => {
        const last = event.results.length - 1;
        const transcript = event.results[last][0].transcript.toLowerCase().trim().replace('.', '');

        this.lastTranscript.set(transcript);

        const number = this.wordToNumberMap[transcript];

        if (number !== undefined) {
          this.recognizedNumberSubject.next(number);
        }
      };

      this.recognition.onspeechend = () => {
        this.stopListening();
      };

      this.recognition.onnomatch = () => {
        this.error.set("I didn't recognize that number.");
        this.stopListening();
      }

      this.recognition.onerror = (event: any) => {
        let errorMessage = event.error;
        if (event.error === 'no-speech') {
            errorMessage = "I didn't hear anything. Please speak clearly.";
        } else if (event.error === 'audio-capture') {
            errorMessage = "There's an issue with your microphone.";
        } else if (event.error === 'not-allowed') {
            errorMessage = "Microphone access is blocked. Please allow it in your browser settings.";
        }
        this.error.set(errorMessage);
        this.stopListening();
      };
    } catch (e) {
        this.isSupported.set(false);
        this.microphoneDetected.set(false);
        this.error.set('Could not initialize speech recognition.');
    }
  }

  private async checkMicrophonePresence() {
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
          this.microphoneDetected.set(false);
          return;
      }

      try {
          const devices = await navigator.mediaDevices.enumerateDevices();
          const hasMicrophone = devices.some(d => d.kind === 'audioinput');
          this.microphoneDetected.set(hasMicrophone);
      } catch (e) {
          this.microphoneDetected.set(false);
      }
  }

  startListening() {
    if (!this.isSupported() || this.isListening()) {
        return;
    }
    this.isListening.set(true);
    this.error.set(null);
    this.lastTranscript.set('');
    try {
        this.recognition.start();
    } catch(e) {
        this.isListening.set(false);
        this.error.set("Microphone already in use.");
    }
  }

  stopListening() {
    if (!this.isSupported() || !this.isListening()) {
        return;
    }
    this.isListening.set(false);
    this.recognition.stop();
  }
}

