import { Injectable, signal, OnDestroy } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class AudioRecorderService implements OnDestroy {
  isRecording = signal(false);
  isPlaying = signal(false);
  hasRecording = signal(false);
  error = signal<string | null>(null);

  private mediaRecorder: MediaRecorder | null = null;
  private stream: MediaStream | null = null;
  private audioChunks: Blob[] = [];
  private audioBlob: Blob | null = null;
  private audioUrl: string | null = null;
  private audio: HTMLAudioElement | null = null;

  async startRecording() {
    if (this.isRecording()) return;

    this.error.set(null);
    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        this.error.set('Recording API not supported.');
        return;
      }

      this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      this.mediaRecorder = new MediaRecorder(this.stream);

      this.mediaRecorder.ondataavailable = event => {
        this.audioChunks.push(event.data);
      };

      this.mediaRecorder.onstop = () => {
        this.audioBlob = new Blob(this.audioChunks, { type: 'audio/wav' });
        this.audioChunks = [];
        if (this.audioUrl) {
            URL.revokeObjectURL(this.audioUrl);
        }
        this.audioUrl = URL.createObjectURL(this.audioBlob);
        this.hasRecording.set(true);
      };

      this.mediaRecorder.start();
      this.isRecording.set(true);
      this.hasRecording.set(false);

    } catch (err) {
      console.error('Error starting recording:', err);
      this.error.set('Could not start recording. Check microphone permissions.');
      this.cleanupStream();
    }
  }

  stopRecording() {
    if (!this.isRecording() || !this.mediaRecorder) return;

    this.mediaRecorder.stop();
    this.isRecording.set(false);
    this.cleanupStream();
  }

  playRecording() {
    if (!this.audioUrl || this.isPlaying()) return;

    this.audio = new Audio(this.audioUrl);
    this.audio.onplay = () => this.isPlaying.set(true);
    this.audio.onended = () => this.isPlaying.set(false);
    this.audio.onpause = () => this.isPlaying.set(false); // Also handle pause/stop
    this.audio.play();
  }

  private cleanupStream() {
    if (this.stream) {
      this.stream.getTracks().forEach(track => track.stop());
      this.stream = null;
    }
  }

  ngOnDestroy() {
    if (this.audioUrl) {
      URL.revokeObjectURL(this.audioUrl);
    }
    this.cleanupStream();
  }
}

