import { Injectable, signal } from '@angular/core';
import { Subject } from 'rxjs';
import { GoogleGenAI } from '@google/genai';

@Injectable({ providedIn: 'root' })
export class SpeechRecognitionService {
  private ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  private mediaRecorder: MediaRecorder | null = null;
  private stream: MediaStream | null = null;
  private audioChunks: Blob[] = [];

  private audioContext: AudioContext | null = null;
  private analyser: AnalyserNode | null = null;
  private dataArray: Uint8Array | null = null;
  private source: MediaStreamAudioSourceNode | null = null;
  private animationFrameId: number | null = null;
  private silenceDetection = {
      silenceThreshold: 5, // Volume level below which is considered silence
      silenceDuration: 750, // ms of silence to trigger stop
      lastSoundTime: 0,
  };

  private wordToNumberMap: { [key: string]: number } = {
    'zero': 0, 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
    'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10,
    'eleven': 11, 'twelve': 12, 'thirteen': 13, 'fourteen': 14, 'fifteen': 15,
    'sixteen': 16, 'seventeen': 17, 'eighteen': 18, 'nineteen': 19, 'twenty': 20
  };

  isSupported = signal(true);
  microphoneDetected = signal<boolean | 'pending'>('pending');
  isListening = signal(false); // "is recording"
  isProcessing = signal(false);
  error = signal<string | null>(null);
  lastTranscript = signal<string>('');
  private recognizedNumberSubject = new Subject<number>();
  recognizedNumber$ = this.recognizedNumberSubject.asObservable();

  constructor() {
    this.checkMicrophonePresence();
  }

  private async checkMicrophonePresence() {
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
          this.microphoneDetected.set(false);
          return;
      }
      try {
          const devices = await navigator.mediaDevices.enumerateDevices();
          const hasMicrophone = devices.some(d => d.kind === 'audioinput');
          this.microphoneDetected.set(hasMicrophone);
      } catch (e) {
          this.microphoneDetected.set(false);
      }
  }

  async startListening() {
    if (this.isListening() || this.isProcessing()) return;

    this.error.set(null);
    this.lastTranscript.set('');

    try {
        this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        this.mediaRecorder = new MediaRecorder(this.stream);
        this.audioChunks = [];

        this.mediaRecorder.ondataavailable = event => {
            this.audioChunks.push(event.data);
        };

        this.mediaRecorder.onstop = async () => {
            const audioBlob = new Blob(this.audioChunks, { type: 'audio/wav' });
            this.cleanupStream();
            if (audioBlob.size > 0) {
              this.transcribeWithGemini(audioBlob);
            } else {
              this.isProcessing.set(false);
            }
        };

        this.mediaRecorder.start();
        this.isListening.set(true);
        this.startSilenceDetection(this.stream);

    } catch (err) {
        console.error('Error starting recording:', err);
        this.error.set('Could not start recording. Check microphone permissions.');
        this.cleanupStream();
        this.isListening.set(false);
    }
  }

  stopListening() {
    if (!this.isListening()) return;

    this.stopSilenceDetection();

    if (this.mediaRecorder && this.mediaRecorder.state === 'recording') {
        this.mediaRecorder.stop();
    }
    this.isListening.set(false);
    this.isProcessing.set(true);
  }

  private async transcribeWithGemini(audioBlob: Blob) {
    this.lastTranscript.set('');
    try {
        const base64Audio = await this.blobToBase64(audioBlob);

        const audioPart = { inlineData: { mimeType: 'audio/wav', data: base64Audio } };
        const textPart = { text: "Transcribe the number spoken in the audio. The number will be between zero and twenty. Respond with only the single number word in lowercase, for example: 'four'." };

        const response = await this.ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: { parts: [audioPart, textPart] },
        });

        const transcript = response.text.trim().toLowerCase();
        this.lastTranscript.set(transcript);

        const number = this.wordToNumberMap[transcript];
        if (number !== undefined) {
            this.recognizedNumberSubject.next(number);
        } else {
            this.error.set(`Heard "${transcript}", but couldn't identify a number.`);
        }

    } catch (e) {
        console.error('Error with Gemini API:', e);
        this.error.set('Speech processing failed. Please try again.');
    } finally {
        this.isProcessing.set(false);
    }
  }

  private blobToBase64(blob: Blob): Promise<string> {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
            const dataUrl = reader.result as string;
            const base64 = dataUrl.split(',')[1];
            resolve(base64);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });
  }

  private startSilenceDetection(stream: MediaStream) {
    try {
        this.audioContext = new AudioContext();
        this.analyser = this.audioContext.createAnalyser();
        this.source = this.audioContext.createMediaStreamSource(stream);
        this.analyser.fftSize = 256;
        const bufferLength = this.analyser.frequencyBinCount;
        this.dataArray = new Uint8Array(bufferLength);
        this.source.connect(this.analyser);
        this.silenceDetection.lastSoundTime = Date.now();
        this.detect();
    } catch(e) {
        console.error("Could not start silence detection", e);
    }
}

  private detect = () => {
      if (!this.isListening() || !this.analyser || !this.dataArray) return;

      this.animationFrameId = requestAnimationFrame(this.detect);
      this.analyser.getByteTimeDomainData(this.dataArray);

      let sumSquares = 0.0;
      for (const amplitude of this.dataArray) {
          const normalizedSample = (amplitude / 128.0) - 1.0;
          sumSquares += normalizedSample * normalizedSample;
      }

      const rms = Math.sqrt(sumSquares / this.dataArray.length);
      const volumeLevel = rms * 250;

      if (volumeLevel > this.silenceDetection.silenceThreshold) {
          this.silenceDetection.lastSoundTime = Date.now();
      }

      if (Date.now() - this.silenceDetection.lastSoundTime > this.silenceDetection.silenceDuration) {
          this.stopListening();
      }
  };

  private stopSilenceDetection() {
      if (this.animationFrameId) {
          cancelAnimationFrame(this.animationFrameId);
          this.animationFrameId = null;
      }
      if(this.audioContext && this.audioContext.state !== 'closed') {
          this.audioContext.close();
      }
  }

  private cleanupStream() {
    this.stopSilenceDetection();
    if (this.stream) {
      this.stream.getTracks().forEach(track => track.stop());
      this.stream = null;
    }
  }
}

