      this.isModelReady.set(true);
    } catch (e) {
      console.error('Failed to load speech model:', e);
      this.modelLoadingError.set('Could not load speech model. Please refresh.');
      this.isSupported.set(false);
    }
  }

  private async checkMicrophonePresence() {
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
          this.microphoneDetected.set(false);
          return;
      }
      try {
          const devices = await navigator.mediaDevices.enumerateDevices();
          const hasMicrophone = devices.some(d => d.kind === 'audioinput');
          this.microphoneDetected.set(hasMicrophone);
      } catch (e) {
          this.microphoneDetected.set(false);
      }
  }

  async startListening() {
    if (this.isListening() || !this.workletURL) return;

    this.error.set(null);
    this.lastTranscript.set('');
    this.audioBuffer = [];

    try {
        this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        this.audioContext = new AudioContext();

        await this.audioContext.audioWorklet.addModule(this.workletURL);
        this.micSource = this.audioContext.createMediaStreamSource(this.stream);
        this.workletNode = new AudioWorkletNode(this.audioContext, 'vad-worklet-processor', {
            processorOptions: {
                vadThreshold: 0.01,
                silenceTimeout: 800, // Process after 800ms of silence
            }
        });

        this.workletNode.port.onmessage = (event) => {
            switch (event.data.type) {
                case 'audio_chunk':
                    this.audioBuffer.push(event.data.chunk);
                    break;
                case 'speech_end':
                    this.processAudio();
                    break;
            }
        };

        this.micSource.connect(this.workletNode);
        this.isListening.set(true);

    } catch (e) {
        console.error('Error starting real-time recording:', e);
        this.error.set('Could not access microphone. Please check permissions.');
        this.cleanupAudio();
    }
  }

  async stopListening() {
    if (!this.isListening()) return;

    if (this.audioBuffer.length > 0) {
      await this.processAudio();
    }

    this.cleanupAudio();
  }

  private async processAudio() {
    if (this.audioBuffer.length === 0 || !this.transcriber) {
        return;
    }

    this.isProcessing.set(true);

    try {
        const totalLength = this.audioBuffer.reduce((sum, chunk) => sum + chunk.length, 0);
        const concatenated = new Float32Array(totalLength);
        let offset = 0;
        for (const chunk of this.audioBuffer) {
            concatenated.set(chunk, offset);
            offset += chunk.length;
        }
        this.audioBuffer = []; 

        const resampled = await this.resample(concatenated, this.audioContext!.sampleRate, 16000);

        const output = await this.transcriber(resampled);
        const transcript = (output.text as string || '').trim();

        if (transcript && !transcript.toLowerCase().includes('[blank audio]')) {
             this.lastTranscript.set(transcript);
             this.parseTranscriptForNumber(transcript);
        } else if (this.lastTranscript() === '') {
            this.error.set("I didn't hear anything clearly.");
        }

    } catch (e) {
        console.error('Error processing audio:', e);
        this.error.set('Could not understand audio. Please try again.');
    } finally {
        this.isProcessing.set(false);
    }
  }

  private parseTranscriptForNumber(transcript: string) {
    const words = transcript.toLowerCase().replace(/[.,?\/#!$%\^&\*;:{}=\-_`~()]/g,"").split(' ');
    let numberFound = false;
    for (const word of words) {
        let number = this.wordToNumberMap[word];
        if (number === undefined) {
            const parsedNumber = parseInt(word, 10);
            if (!isNaN(parsedNumber)) {
                number = parsedNumber;
            }
        }
        if (number !== undefined) {
            this.recognizedNumberSubject.next(number);
            numberFound = true;
            break;
        }
    }
    if (!numberFound) {
        this.error.set("I heard you, but didn't recognize a number.");
    }
  }

  private async resample(audioData: Float32Array, inputRate: number, outputRate: number): Promise<Float32Array> {
    if (inputRate === outputRate) {
        return audioData;
    }
    const offlineCtx = new OfflineAudioContext(1, (audioData.length * outputRate) / inputRate, outputRate);
    const buffer = offlineCtx.createBuffer(1, audioData.length, inputRate);
    buffer.copyToChannel(audioData, 0);

    const source = offlineCtx.createBufferSource();
    source.buffer = buffer;
    source.connect(offlineCtx.destination);
    source.start(0);

    const renderedBuffer = await offlineCtx.startRendering();
    return renderedBuffer.getChannelData(0);
  }

  private cleanupAudio() {
    this.isListening.set(false);
    this.workletNode?.port.postMessage({ type: 'stop' });
    this.workletNode?.disconnect();
    this.micSource?.disconnect();
    this.stream?.getTracks().forEach(track => track.stop());
    if (this.audioContext && this.audioContext.state !== 'closed') {
        this.audioContext.close();
    }

    this.workletNode = null;
    this.micSource = null;
    this.stream = null;
    this.audioContext = null;
    this.audioBuffer = [];
  }

  ngOnDestroy() {
    this.cleanupAudio();
    if (this.workletURL) {
      URL.revokeObjectURL(this.workletURL);
    }
  }
}

import { Injectable, signal, OnDestroy } from '@angular/core';
import { Subject } from 'rxjs';
import { pipeline, AutomaticSpeechRecognitionPipeline } from '@xenova/transformers';

// This AudioWorklet code will be loaded into a separate thread to process audio
// in real-time without blocking the main UI thread. It performs simple Voice
// Activity Detection (VAD) to only send audio chunks when the user is speaking.
const vadWorkletCode = `
class VADWorkletProcessor extends AudioWorkletProcessor {
    constructor(options) {
        super();
        this.vadThreshold = options.processorOptions.vadThreshold;
        this.silenceTimeout = options.processorOptions.silenceTimeout;
        this.isSpeaking = false;
        this.silenceTimer = -1;
    }

    calculateRMS(chunk) {
        let sumSquares = 0.0;
        for (const sample of chunk) {
            sumSquares += sample * sample;
        }
        return Math.sqrt(sumSquares / chunk.length);
    }

    process(inputs, outputs, parameters) {
        // We expect mono audio.
        const inputChannel = inputs[0][0];

        if (inputChannel) {
            const rms = this.calculateRMS(inputChannel);

            if (rms > this.vadThreshold) {
                if (!this.isSpeaking) {
                    this.isSpeaking = true;
                }
                clearTimeout(this.silenceTimer);
                this.silenceTimer = -1;
                // Post a copy of the audio data back to the main thread
                this.port.postMessage({ type: 'audio_chunk', chunk: inputChannel.slice() });
            } else if (this.isSpeaking) {
                 if (this.silenceTimer === -1) {
                    this.silenceTimer = setTimeout(() => {
                        this.isSpeaking = false;
                        // Let the main thread know that speech has ended
                        this.port.postMessage({ type: 'speech_end' });
                        this.silenceTimer = -1;
                    }, this.silenceTimeout);
                 }
            }
        }
        return true; // Keep processor alive
    }
}
registerProcessor('vad-worklet-processor', VADWorkletProcessor);
`;

